import{_ as p,o as t,c as r,j as a,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"M45战术霰弹枪","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/1.D级/M45战术霰弹枪.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/1.D级/M45战术霰弹枪.md"}'),s={name:"4.资源分区/7.物品与装备/2.武器/远程武器/1.D级/M45战术霰弹枪.md"};function d(l,e,i,_,c,h){return t(),r("div",null,[...e[0]||(e[0]=[a("h1",{id:"m45战术霰弹枪",tabindex:"-1"},[n("M45战术霰弹枪 "),a("a",{class:"header-anchor",href:"#m45战术霰弹枪","aria-label":'Permalink to "M45战术霰弹枪"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘")])])],-1),o('<h1 id="m45战术霰弹枪-1" tabindex="-1">M45战术霰弹枪 <a class="header-anchor" href="#m45战术霰弹枪-1" aria-label="Permalink to &quot;M45战术霰弹枪&quot;">​</a></h1><p>M45 Tactical Shotgun?/?M45战术霰弹枪</p><p>Tactical Shotgun, 8 Gauge, Pump Action, M45 /?M45八号口径泵动战术霰弹枪，由米斯利亚军械库制造。用于大多数近距离作战场景（特别是在敌占的城市地区），以及登舰行动。大反叛期间，它曾在城市地形环境下的许多军事行动中使用，并受到使用者的广泛好评。它后来在人类星盟战争期间和战后被继续广泛使用。</p><p>价格：D+500</p><p>本质：科技</p><p>制造商：米斯利亚军械库</p><p>类型：战术霰弹枪</p><p>长度：112.9 厘米（44.4 英寸）</p><p>宽度：11.2 厘米（4.4 英寸）</p><p>高度：24.4 厘米（9.6 英寸）</p><p>重量：3.6 千克（7.9 磅）</p><p>弹药类型：M296 8号铅径马格南（1分50发）</p><p>供弹系统：11 / 12发不可拆卸管状弹仓</p><p>操作原理：泵动式</p><p>有效射程：40</p><p>力量需求：6</p><p>武器伤害：7L</p><p>基础特性：【制止力】【贯穿】</p><p>【制止力】<br> M45战术霰弹枪是一部双管式、不可拆卸的内置管状弹仓，使用8铅径弹药。它是一种特殊用途武器，用于交战范围有限的情况，以及不需要过度火力，但需要输出最大制止力的情况。 当使用M45战术霰弹枪对目标造成伤害时，每造成1点伤害，被攻击的对象将被击退1米，对方可以选择以力量+运动：反射进行对抗判定抵挡，或者以敏捷+运动：反射进行对抗避开（或至少抵消冲撞的力道）</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',21)])])}const f=p(s,[["render",d]]);export{m as __pageData,f as default};
